UPDATE public.questions SET
  stimulus_text = NULL,
  question_text = 'Which choice correctly punctuates the following sentence?
The ancient Greek philosopher Socrates believed that a life unexamined was not worth living, and that the pursuit of knowledge and wisdom was essential to a fulfilling existence. ',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The ancient Greek philosopher Socrates believed that a life unexamined was not worth living, and that the pursuit of knowledge and wisdom was essential to a fulfilling existence.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"B","text":"The ancient Greek philosopher Socrates believed that a life unexamined was not worth living; and that the pursuit of knowledge and wisdom was essential to a fulfilling existence.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"C","text":"The ancient Greek philosopher Socrates believed that a life unexamined was not worth living, and; that the pursuit of knowledge and wisdom was essential to a fulfilling existence.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"D","text":"The ancient Greek philosopher Socrates believed that a life unexamined was not worth living; that the pursuit of knowledge and wisdom was essential to a fulfilling existence.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The correct answer is A.  A comma is used to separate two independent clauses that are joined by a coordinating conjunction.  Semicolons are used to separate two independent clauses that are not joined by a coordinating conjunction, but the two clauses must be closely related. A semicolon can also be used to separate items in a series when there is a comma within the series. A dash is used to separate a parenthetical element from the rest of the sentence.  A colon can be used to introduce a list or a series.  In this sentence, the two independent clauses are joined by the coordinating conjunction "and."  Therefore, a comma is the correct punctuation to separate the two independent clauses. Choices B, C, and D are incorrect because they use incorrect punctuation to separate the two independent clauses. Choice A is correct because it aligns with that evidence: The ancient Greek philosopher Socrates believed that a life unexamined was not worth living, and tha…. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked. On the Digital SAT, the best explanation ties the correct answer to specific language in the stimulus rather than relying on outside knowledge alone.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":1046,"opensat_domain":"Standard English Conventions","opensat_raw_id":"a3f8c42b","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.903Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
WHERE id = 'a76d3057-983e-4da1-baa6-2451e773bf0c';
