UPDATE public.questions SET
  stimulus_text = 'A recent study found that people who eat breakfast regularly are more likely to have a healthy weight than those who skip breakfast. However, the researchers cautioned that their findings do not prove that breakfast causes weight loss. What is the most likely reason why the researchers cautioned that their findings do not prove that breakfast causes weight loss?',
  question_text = 'The researchers’ caution likely reflects an understanding that',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"a correlation does not always imply causation.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"a healthy diet is more important than regular breakfast habits.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"breakfast is only one factor that contributes to a healthy weight.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"most people who eat breakfast regularly are already health-conscious.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The researchers’ caution reflects the understanding that correlation does not always imply causation. The fact that people who eat breakfast regularly are more likely to have a healthy weight does not mean that breakfast causes weight loss. Other factors could be responsible for the correlation, such as those people being more likely to engage in regular exercise or to make healthier food choices in general. The passage states that "A recent study found that people who eat breakfast regularly are more likely to have a healthy weight than those who ski…", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: a correlation does not always imply causation.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":1029,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_a4","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.904Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
